/**
 * AdminLens — single eth_call that returns all admin dashboard data.
 *
 * Uses the constructor-only pattern (like TradeLensV2): bytecode is sent
 * via eth_call, executes in a simulated deployment, and returns encoded
 * data via assembly. No contract deployment, no state changes.
 */

import { ethers } from 'ethers';

// Compiled bytecode of AdminLens.sol
// ⚠ Keep in sync: copy from solidty-contracts/artifacts/contracts/simulators/AdminLens.sol/AdminLens.json → "bytecode"
const BYTECODE =
	'';

// ABI decode types — must match AdminLens.sol struct layout
const FACTORY_STATE_TYPE =
	'tuple(address owner, uint256 totalTokens, uint256 totalFeeUsdt, uint256[8] feesPerType, uint256[8] countPerType, bool taxToStable, uint256 taxSlippage, uint8 refLevels, bool autoDistribute, address dexRouter, address usdt, uint8 usdtDecimals, address authorizedRouter, address platformWallet, address[] partnerBases, uint256 maxPartnerBases)';

const LAUNCHPAD_STATE_TYPE =
	'tuple(address owner, uint256 totalLaunches, uint256 totalFeeUsdt, uint256 launchFee, address platformWallet, address dexRouter, address usdt, address authorizedRouter, address launchImplementation)';

const TRADE_ROUTER_STATE_TYPE =
	'tuple(address owner, uint256 feeBps, uint256 payoutTimeout, address platformWallet, uint256 totalEscrow, uint256 pendingCount, uint256 totalWithdrawals, bool paused, uint256 maxSlippageBps, bool affiliateEnabled, uint256 affiliateShareBps, uint256 minWithdrawUsdt, uint256 platformEarningsUsdt)';

const TOKEN_INFO_TYPE =
	'tuple(address token, string name, string symbol, uint8 decimals, uint256 totalSupply, address creator, address owner, bool isMintable, bool isTaxable, bool isPartner)[]';

const LAUNCH_INFO_TYPE =
	'tuple(address launch, address token, string tokenName, string tokenSymbol, uint8 tokenDecimals, address creator, uint8 curveType, uint8 state, uint256 softCap, uint256 hardCap, uint256 deadline, uint256 startTimestamp, uint256 totalBaseRaised, uint256 tokensSold, uint256 tokensForCurve, uint256 tokensForLP, uint256 currentPrice, uint256 totalPurchases, uint256 totalBuyers)[]';

const RESULT_TYPES = [FACTORY_STATE_TYPE, LAUNCHPAD_STATE_TYPE, TRADE_ROUTER_STATE_TYPE, TOKEN_INFO_TYPE, LAUNCH_INFO_TYPE];

export interface FactoryState {
	owner: string;
	totalTokens: number;
	totalFeeUsdt: bigint;
	feesPerType: bigint[];
	countPerType: number[];
	taxToStable: boolean;
	taxSlippage: number;
	refLevels: number;
	autoDistribute: boolean;
	dexRouter: string;
	usdt: string;
	usdtDecimals: number;
	authorizedRouter: string;
	platformWallet: string;
	partnerBases: string[];
	maxPartnerBases: number;
}

export interface LaunchpadState {
	owner: string;
	totalLaunches: number;
	totalFeeUsdt: bigint;
	launchFee: bigint;
	platformWallet: string;
	dexRouter: string;
	usdt: string;
	authorizedRouter: string;
	launchImplementation: string;
}

export interface TradeRouterState {
	owner: string;
	feeBps: number;
	payoutTimeout: number;
	platformWallet: string;
	totalEscrow: bigint;
	pendingCount: number;
	totalWithdrawals: number;
	paused: boolean;
	maxSlippageBps: number;
	affiliateEnabled: boolean;
	affiliateShareBps: number;
	minWithdrawUsdt: bigint;
	platformEarningsUsdt: bigint;
}

export interface TokenInfo {
	token: string;
	name: string;
	symbol: string;
	decimals: number;
	totalSupply: bigint;
	creator: string;
	owner: string;
	isMintable: boolean;
	isTaxable: boolean;
	isPartner: boolean;
}

export interface LaunchInfo {
	launch: string;
	token: string;
	tokenName: string;
	tokenSymbol: string;
	tokenDecimals: number;
	creator: string;
	curveType: number;
	state: number;
	softCap: bigint;
	hardCap: bigint;
	deadline: number;
	startTimestamp: number;
	totalBaseRaised: bigint;
	tokensSold: bigint;
	tokensForCurve: bigint;
	tokensForLP: bigint;
	currentPrice: bigint;
	totalPurchases: number;
	totalBuyers: number;
}

export interface AdminLensResult {
	factory: FactoryState;
	launchpad: LaunchpadState;
	tradeRouter: TradeRouterState;
	recentTokens: TokenInfo[];
	recentLaunches: LaunchInfo[];
}

/**
 * Fetch all admin dashboard data in a single eth_call.
 */
export async function queryAdminLens(
	provider: ethers.Provider,
	tokenFactory: string,
	launchpadFactory: string,
	tradeRouter: string = ethers.ZeroAddress,
	recentTokenCount = 10,
	recentLaunchCount = 10,
): Promise<AdminLensResult> {
	const abiCoder = ethers.AbiCoder.defaultAbiCoder();
	const args = abiCoder.encode(
		['address', 'address', 'address', 'uint256', 'uint256'],
		[tokenFactory, launchpadFactory, tradeRouter, recentTokenCount, recentLaunchCount],
	);

	const raw = await provider.call({
		data: BYTECODE + args.slice(2),
		gasLimit: 30_000_000,
	});

	const decoded = abiCoder.decode(RESULT_TYPES, raw);

	const fs = decoded[0];
	const factory: FactoryState = {
		owner: fs.owner,
		totalTokens: Number(fs.totalTokens),
		totalFeeUsdt: fs.totalFeeUsdt,
		feesPerType: [...fs.feesPerType],
		countPerType: [...fs.countPerType].map(Number),
		taxToStable: fs.taxToStable,
		taxSlippage: Number(fs.taxSlippage),
		refLevels: Number(fs.refLevels),
		autoDistribute: fs.autoDistribute,
		dexRouter: fs.dexRouter,
		usdt: fs.usdt,
		usdtDecimals: Number(fs.usdtDecimals),
		authorizedRouter: fs.authorizedRouter,
		platformWallet: fs.platformWallet,
		partnerBases: [...(fs.partnerBases || [])],
		maxPartnerBases: Number(fs.maxPartnerBases || 0),
	};

	const lp = decoded[1];
	const launchpad: LaunchpadState = {
		owner: lp.owner,
		totalLaunches: Number(lp.totalLaunches),
		totalFeeUsdt: lp.totalFeeUsdt,
		launchFee: lp.launchFee,
		platformWallet: lp.platformWallet,
		dexRouter: lp.dexRouter,
		usdt: lp.usdt,
		authorizedRouter: lp.authorizedRouter,
		launchImplementation: lp.launchImplementation,
	};

	const tr = decoded[2];
	const tradeRouterState: TradeRouterState = {
		owner: tr.owner,
		feeBps: Number(tr.feeBps),
		payoutTimeout: Number(tr.payoutTimeout),
		platformWallet: tr.platformWallet,
		totalEscrow: tr.totalEscrow,
		pendingCount: Number(tr.pendingCount),
		totalWithdrawals: Number(tr.totalWithdrawals),
		paused: tr.paused,
		maxSlippageBps: Number(tr.maxSlippageBps),
		affiliateEnabled: tr.affiliateEnabled,
		affiliateShareBps: Number(tr.affiliateShareBps),
		minWithdrawUsdt: tr.minWithdrawUsdt,
		platformEarningsUsdt: tr.platformEarningsUsdt,
	};

	const recentTokens: TokenInfo[] = (decoded[3] as any[]).map((t: any) => ({
		token: t.token,
		name: t.name,
		symbol: t.symbol,
		decimals: Number(t.decimals),
		totalSupply: t.totalSupply,
		creator: t.creator,
		owner: t.owner,
		isMintable: t.isMintable,
		isTaxable: t.isTaxable,
		isPartner: t.isPartner,
	}));

	const recentLaunches: LaunchInfo[] = (decoded[4] as any[]).map((l: any) => ({
		launch: l.launch,
		token: l.token,
		tokenName: l.tokenName,
		tokenSymbol: l.tokenSymbol,
		tokenDecimals: Number(l.tokenDecimals),
		creator: l.creator,
		curveType: Number(l.curveType),
		state: Number(l.state),
		softCap: l.softCap,
		hardCap: l.hardCap,
		deadline: Number(l.deadline),
		startTimestamp: Number(l.startTimestamp),
		totalBaseRaised: l.totalBaseRaised,
		tokensSold: l.tokensSold,
		tokensForCurve: l.tokensForCurve,
		tokensForLP: l.tokensForLP,
		currentPrice: l.currentPrice,
		totalPurchases: Number(l.totalPurchases),
		totalBuyers: Number(l.totalBuyers),
	}));

	return { factory, launchpad, tradeRouter: tradeRouterState, recentTokens, recentLaunches };
}
